config.script:
// t.co -> tickets.la28.org can redirect CLIENT-SIDE (after domcontentloaded), so
// a single check - even after a fixed settle - races the redirect on a slow
// proxy and reads t.co / an intermediate, missing the block. POLL instead: keep
// looking until we either see Akamai's "Access Denied" (throw, so the run
// rotates proxy) or the real LA28 page (continue). Navigations during the poll
// destroy this isolated world; the engine retries the whole node on the settled
// page, so the poll always ends up on the final document.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function denied(){
  var title=(document.title||'').trim();
  var body=(document.body?document.body.innerText:'')||'';
  return /access denied/i.test(title)
    || (/access denied/i.test(body) && /(don't have permission|reference #|edgesuite\.net)/i.test(body));
}
function la28Ready(){
  // Positive proof we reached the real LA28 site (not t.co / an intermediate) so
  // we can stop early on a clean run instead of polling the full window.
  var title=(document.title||'').trim();
  if(/official la28|la28.*(ticket|olympic|paralympic)/i.test(title)) return true;
  var host=(location.host||'');
  var body=(document.body?document.body.innerText:'')||'';
  return /la28\.org/i.test(host)
    && /register for the la28|get tickets|waiting room|create an account|legal terms and privacy|mark your calendar/i.test(body);
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+20000;
while(Date.now()<deadline){
  if(denied()) throw new Error('LA28 Access Denied - this proxy IP is blocked. Use a different proxy.');
  if(la28Ready()) return (document.title||'').trim();
  await sleep(500);
}
if(denied()) throw new Error('LA28 Access Denied - this proxy IP is blocked. Use a different proxy.');
return (document.title||'').trim();

// After the queue-join / botdetect click, Queue-it either sends us into the
// waiting room or - if the IP is flagged - to /queue/error403 ("We are sorry,
// your access has been restricted"). It takes a moment to decide, so check ONCE
// too early (the old bug) races the redirect and misses the block - then the
// next step hangs 300s on a dead page. Wait for load, then POLL until we either
// see the block (throw, so the run rotates proxy) or the waiting-room proceed
// element appears (continue).
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function blocked(){
  var title=(document.title||'').trim();
  var body=(document.body?document.body.innerText:'')||'';
  var href=location.href||'';
  return /access denied|restricted access/i.test(title)
    || /error403|queue-it\.net/i.test(href)
    || /your access has been restricted|access has been restricted/i.test(body);
}
function proceedReady(){
  try{
    var el=document.evaluate('/html/body/div[2]/div[2]/div[3]/a/div',document,null,XPathResult.FIRST_ORDERED_NODE_TYPE,null).singleNodeValue;
    if(el){var r=el.getBoundingClientRect();return r.width>0&&r.height>0;}
  }catch(e){}
  return false;
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<45000){await sleep(200);}
var deadline=Date.now()+12000;
while(Date.now()<deadline){
  if(blocked()) throw new Error('LA28 blocked (Akamai/Queue-it): this proxy IP is flagged - rotating to a fresh proxy.');
  if(proceedReady()) break;
  await sleep(500);
}
if(blocked()) throw new Error('LA28 blocked (Akamai/Queue-it): this proxy IP is flagged - rotating to a fresh proxy.');
try { var b = document.querySelector('button.cmpwelcomebtnyes'); if (b) b.click(); } catch (e) {}
return (document.title||'').trim();

const el = document.evaluate('/html/body/div[2]/div[2]/div[3]/a/div', document, null, XPathResult.FIRST_ORDERED_NODE_TYPE, null).singleNodeValue;
if (!el) return '';
const r = el.getBoundingClientRect();
return (r.width > 0 && r.height > 0) ? '1' : '';

// Dismiss LA28's first-load consent gate ("Legal Terms and Privacy" CONTINUE,
// and/or a cookie CMP). Searches the main DOM, OPEN shadow roots, and
// same-origin iframes for the consent button (by id or exact visible text),
// prefers one inside a modal/overlay, clicks it, and confirms it closed.
// If nothing reachable is found it throws a DIAG string listing iframes +
// shadow hosts so the exact structure (e.g. a cross-origin CMP iframe) is known.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){
  if(!el)return false;
  var r=el.getBoundingClientRect();
  if(r.width<2||r.height<2)return false;
  var s=getComputedStyle(el);
  if(s.visibility==='hidden'||s.display==='none'||parseFloat(s.opacity||'1')<0.05)return false;
  var W=window.innerWidth||9999,H=window.innerHeight||9999;
  if(r.bottom<0||r.top>H||r.right<0||r.left>W)return false;
  return true;
}
function parentOf(n){
  var p=n.parentElement;
  if(!p){var rt=n.getRootNode&&n.getRootNode();p=(rt&&rt.host)||null;}
  return p;
}
function inOverlay(el){
  var n=el;
  while(n&&n.nodeType===1){
    if(n.getAttribute&&(n.getAttribute('role')==='dialog'||n.getAttribute('aria-modal')==='true'))return true;
    try{var s=getComputedStyle(n);if((s.position==='fixed'||s.position==='sticky')&&parseInt(s.zIndex||'0',10)>=5)return true;}catch(e){}
    if(n===document.body)break;
    n=parentOf(n);
  }
  return false;
}
function clickIt(el){
  var t=(el.closest&&el.closest('button, a, [role=button], input[type=submit], input[type=button], [onclick]'))||el;
  try{t.scrollIntoView({block:'center'});}catch(e){}
  try{t.click();}catch(e){}
  if(t!==el){try{el.click();}catch(e){}}
}
function allRoots(){
  var roots=[document],stack=[document];
  while(stack.length){
    var root=stack.pop(),els;
    try{els=root.querySelectorAll('*');}catch(e){continue;}
    for(var i=0;i<els.length;i++){var sh=els[i].shadowRoot;if(sh){roots.push(sh);stack.push(sh);}}
  }
  var ifr=document.querySelectorAll('iframe');
  for(var j=0;j<ifr.length;j++){var dd=null;try{dd=ifr[j].contentDocument;}catch(e){}if(dd)roots.push(dd);}
  return roots;
}
function findIn(root){
  try{var byId=root.querySelector('#cmpbntyestxt');if(byId&&vis(byId))return byId;}catch(e){}
  var exact=/^(continue|i agree|agree|accept all|accept cookies|accept|allow all|got it|ok)$/i;
  var nodes;
  try{nodes=root.querySelectorAll('button, a, [role=button], input[type=submit], input[type=button], span, div, p');}catch(e){return null;}
  var best=null;
  for(var i=0;i<nodes.length;i++){
    var el=nodes[i];
    if(!vis(el))continue;
    var txt=(el.innerText||el.textContent||el.value||'').replace(/\s+/g,' ').trim();
    if(!exact.test(txt))continue;
    var r=el.getBoundingClientRect();
    if(r.height>140||r.width>900)continue;
    if(inOverlay(el))return el;
    if(!best)best=el;
  }
  return best;
}
function pick(){var roots=allRoots();for(var i=0;i<roots.length;i++){var el=findIn(roots[i]);if(el)return el;}return null;}
function diag(){
  var out={rs:document.readyState,iframes:[],shadowHosts:[],btns:[]};
  var ifr=document.querySelectorAll('iframe');
  for(var i=0;i<ifr.length;i++){var co;try{co=ifr[i].contentDocument?'same':'cross';}catch(e){co='cross';}out.iframes.push(((ifr[i].src||'no-src').slice(0,90))+' ['+co+']');}
  var all=document.querySelectorAll('*');
  for(var j=0;j<all.length;j++){if(all[j].shadowRoot)out.shadowHosts.push(all[j].tagName.toLowerCase()+(all[j].id?('#'+all[j].id):''));}
  var cl=document.querySelectorAll('button, a, [role=button], input[type=submit], input[type=button]');
  for(var k=0;k<cl.length&&out.btns.length<20;k++){if(vis(cl[k])){var t=(cl[k].innerText||cl[k].value||'').replace(/\s+/g,' ').trim().slice(0,28);if(t)out.btns.push(t);}}
  return out;
}
var start=Date.now();
while(document.readyState!=='complete'&&Date.now()-start<15000){await sleep(200);}
var deadline=Date.now()+45000;
while(Date.now()<deadline){
  var el=pick();
  if(el){clickIt(el);await sleep(700);if(!vis(el))return 'consent-clicked';}
  await sleep(400);
}
return 'consent-not-found';

// Queue-it sometimes replaces the waiting room with a picture-code human
// verification challenge. This module cannot solve that queue-level challenge,
// so stop the run immediately rather than clicking it or waiting forever.
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
var body=(document.body?document.body.innerText:'')||'';
var copy=/complete this quick step to confirm you.?re a human/i.test(body)||(/enter the code from the picture/i.test(body)&&/i.?m not a robot/i.test(body));
var image=document.querySelector('img[src*="captcha" i],img[id*="captcha" i],img[class*="captcha" i],[id*="botdetect" i] img,[class*="botdetect" i] img');
var input=document.querySelector('input[id*="captcha" i],input[name*="captcha" i],[id*="botdetect" i] input[type="text"],[class*="botdetect" i] input[type="text"]');
if(copy||(visible(image)&&visible(input)))throw new Error('LA28 queue human-verification challenge detected - stopping this run.');
return 'clear';

// Route the current LA28 state. Gigya renders many hidden template forms, so
// scan every selector match and choose a visible element rather than querySelector's
// first (usually hidden) match.
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
function first(sels){for(var i=0;i<sels.length;i++){var nodes=[];try{nodes=document.querySelectorAll(sels[i]);}catch(e){}for(var j=0;j<nodes.length;j++){if(visible(nodes[j]))return nodes[j];}}return null;}
function click(el){try{el.scrollIntoView({block:'center'});}catch(e){}try{el.focus();}catch(e){}el.click();}
var title=(document.title||'').trim(),body=(document.body?document.body.innerText:'')||'',href=(location.href||'').toLowerCase();
if(/error403|access[-_/]?denied|restricted[-_/]?access/.test(href)||/access denied|restricted access/i.test(title)||/your access has been restricted|access has been restricted|you do not have permission to access/i.test(body))throw new Error('LA28 blocked (Akamai/Queue-it): this proxy IP is flagged - rotating to a fresh proxy.');
var email=first(['input[name="username"]','input[name="loginID"]','input[type="email"]','input[autocomplete="username"]']);
var password=first(['input[type="password"][name="password"]','input[type="password"].gigya-input-password','input[type="password"]']);
if(email&&password)return 'login';
if(/profile\s*[-\u2013|]\s*official\s+la28/i.test(title)||first(['app-sports-profile-lotteries','button[data-qa="save-data-button"]']))return 'profile';
var action=first(['#buttonConfirmVisitorPresence','#cmpbntyestxt','button.cmpwelcomebtnyes','a[href*="/mycustomerdata"]','button.botdetect-button','[class*="botdetect"] button']);
if(!action){var all=document.querySelectorAll('button,a,[role=button]');for(var i=0;i<all.length;i++){var txt=(all[i].innerText||all[i].textContent||'').replace(/\s+/g,' ').trim();if(visible(all[i])&&/^(continue|join|confirm)$/i.test(txt)){action=all[i];break;}}}
if(action)click(action);
return 'wait';

// Queue-it periodically asks the visitor to prove they are still present.
// Use its stable element id rather than relying on translated/changing button text.
var b=document.querySelector('#buttonConfirmVisitorPresence');
if(!b)return 'absent';
var r=b.getBoundingClientRect();
var s=getComputedStyle(b);
if(r.width<2||r.height<2||s.visibility==='hidden'||s.display==='none')return 'hidden';
try{b.scrollIntoView({block:'center'});}catch(e){}
try{b.focus();}catch(e){}
b.click();
return 'clicked';

// A successful click is not proof Gigya completed the registration request.
// Wait for a VISIBLE OTP field before starting AYCD; hidden Gigya templates do
// not count. If the registration form remains after 45s, allow one real native
// re-click through the graph, then fail clearly instead of fetching a code that
// can never be entered.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function visible(el){if(!el)return false;var r=el.getBoundingClientRect();var s=getComputedStyle(el);return r.width>1&&r.height>1&&s.visibility!=='hidden'&&s.display!=='none'&&parseFloat(s.opacity||'1')>0.05;}
function first(sels){for(var i=0;i<sels.length;i++){var nodes=[];try{nodes=document.querySelectorAll(sels[i]);}catch(e){}for(var j=0;j<nodes.length;j++){if(visible(nodes[j]))return nodes[j];}}return null;}
function profileReady(){var title=(document.title||'').trim(),href=(location.href||'').toLowerCase();return /profile\s*[-\u2013|]\s*official\s+la28/i.test(title)||/(\/profile|\/mycustomerdata|\/myprofile)/.test(href)||!!first(['app-sports-profile-lotteries','button[data-qa="save-data-button"]']);}
function activeError(){var nodes=[];try{nodes=document.querySelectorAll('.gigya-error-msg-active,[class*="gigya-error-code-"]');}catch(e){}for(var i=0;i<nodes.length;i++){if(!visible(nodes[i]))continue;var txt=(nodes[i].textContent||'').replace(/\s+/g,' ').trim();if(txt)return txt;}return '';}
var attempts=Number("{{la28SubmitState.attempts}}")||1;
var otpSelectors=['input#gigya-textbox-code','form#gigya-otp-update-form input[name="code"]','form#gigya-otp-update-form input[type="text"]'];
var submitSelectors=['#register-site-login input.gigya-input-submit','form#gigya-register-form input[type="submit"]'];
var deadline=Date.now()+45000;
while(Date.now()<deadline){
  if(first(otpSelectors))return {state:'otp',attempts:attempts};
  if(profileReady())return {state:'profile',attempts:attempts};
  var err=activeError();
  if(err){if(/prior olympic|already.*account|click here to log in/i.test(err))throw new Error('email already used');throw new Error('LA28 registration submit failed: '+err.slice(0,240));}
  await sleep(400);
}
if(first(otpSelectors))return {state:'otp',attempts:attempts};
if(profileReady())return {state:'profile',attempts:attempts};
if(first(submitSelectors)&&attempts<2)return {state:'retry',attempts:attempts+1};
throw new Error('LA28 registration submit did not reach the email verification screen after '+attempts+' attempt(s).');

// After the email is entered, give Gigya time to run its server-side check and
// flag an already-registered address (error 400003: "An account from a prior
// Olympic & Paralympic Games exists for this email address. Click here to log
// in."). That case - and only that case - puts a login <a> inside the email
// error span. If it shows, fail fast so this email counts as used.
function sleep(ms){return new Promise(function(r){setTimeout(r,ms);});}
function vis(el){
  if(!el)return false;
  var r=el.getBoundingClientRect();
  if(r.width<1&&r.height<1)return false;
  var s=getComputedStyle(el);
  if(s.visibility==='hidden'||s.display==='none'||parseFloat(s.opacity||'1')<0.05)return false;
  return true;
}
// Blur the email field so Gigya fires its on-blur server validation.
try{
  var em=document.querySelector('#register-site-login input[name="email"]')||document.querySelector('input[name="email"]');
  if(em){em.blur();em.dispatchEvent(new Event('blur',{bubbles:true}));em.dispatchEvent(new Event('change',{bubbles:true}));}
}catch(e){}
// Human wait 6-10s for the async check to come back.
await sleep(6000+Math.floor(Math.random()*4001));
var link=document.querySelector('#gigya-error-msg-gigya-register-form-email > a');
if(link&&vis(link)){
  throw new Error('email already used');
}
return 'email-ok';
